import React from 'react';

const ResultPage = ({ result, teamInfo, onRestart }) => {
  const { score, totalQuestions, timeTaken } = result;

  const formatTime = (microseconds) => {
    const seconds = Math.floor(microseconds / 1_000_000);
    const minutes = Math.floor(seconds / 60);
    const remainingSeconds = seconds % 60;
    return `${minutes}m ${remainingSeconds}s`;
  };

  return (
    <div style={{
      height: '100vh',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      backgroundColor: '#ffffff'
    }}>
      <div style={{
        width: '100%',
        maxWidth: '400px',
        padding: '20px',
        textAlign: 'center'
      }}>
        <h1 style={{ 
          fontSize: '28px', 
          marginBottom: '8px', 
          color: '#000',
          fontWeight: '600'
        }}>
          Quiz Complete!
        </h1>

        <p style={{ 
          color: '#666', 
          marginBottom: '32px', 
          fontSize: '15px'
        }}>
          {teamInfo.teamName}
        </p>

        <div style={{ marginBottom: '32px' }}>
          <div style={{ 
            fontSize: '48px', 
            fontWeight: '600', 
            color: '#000',
            marginBottom: '8px'
          }}>
            {score}/{totalQuestions}
          </div>
          <div style={{ 
            fontSize: '16px', 
            color: '#666'
          }}>
            Time taken: {formatTime(timeTaken)}
          </div>
        </div>

        <button
          onClick={onRestart}
          style={{
            padding: '12px 32px',
            backgroundColor: '#000',
            color: 'white',
            border: 'none',
            borderRadius: '4px',
            fontSize: '16px',
            cursor: 'pointer'
          }}
        >
          Take Another Quiz
        </button>
      </div>
    </div>
  );
};

export default ResultPage;
